package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClassMock;

  // Define a minimal RecordHelper interface for mocking
  interface RecordHelper {
    String[] getRecordComponentNames(Class<?> raw);
  }

  @BeforeAll
  static void setup() {
    recordClassMock = RecordClassMock.class;
  }

  @Test
  void testGetRecordComponentNames_returnsExpected() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      // Mock the RECORD_HELPER field via reflection to a spy that returns a known array
      RecordHelper recordHelperSpy = mock(RecordHelper.class);
      String[] expected = new String[] {"component1", "component2"};
      when(recordHelperSpy.getRecordComponentNames(recordClassMock)).thenReturn(expected);

      // Use reflection to set private static final RECORD_HELPER field
      Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
      recordHelperField.setAccessible(true);

      // Remove final modifier from the field
      Field modifiersField = Field.class.getDeclaredField("modifiers");
      modifiersField.setAccessible(true);
      modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~Modifier.FINAL);

      // Remove the type check by using Unsafe or by setting via reflection without type check
      // but here, the main problem is that the mocked RecordHelper class is not the same as the original RecordHelper interface
      // So we need to create a mock of the actual RecordHelper class, not the interface inside the test class.

      // Get the actual RecordHelper class from ReflectionHelper
      Class<?> recordHelperClass = Class.forName("com.google.gson.internal.reflect.ReflectionHelper$RecordHelper");

      // Create a mock of the actual RecordHelper class
      Object recordHelperMock = mock(recordHelperClass);

      // Set up the mock to return expected when getRecordComponentNames is called
      when(recordHelperClass.getMethod("getRecordComponentNames", Class.class)
          .invoke(recordHelperMock, recordClassMock)).thenReturn(expected);

      // Instead of using 'when' on the proxy, use Mockito's doReturn for the method
      // But since we have the mock object, we can use Mockito's when on the mock object directly:
      // However, due to reflection, better to use Mockito's when like this:
      // But it's complicated; simpler is to use Mockito's Answer or doReturn.

      // So fallback: cast recordHelperMock to the interface and stub
      // But we don't have the interface at compile time.

      // Instead, use Mockito's doReturn:
      Mockito.doReturn(expected).when(recordHelperMock).getClass()
          .getMethod("getRecordComponentNames", Class.class);

      // Actually, better to use Mockito's when on the mock object via reflection:
      // But this is complicated; instead, use a proxy to implement the interface.

      // Alternative approach: use a dynamic proxy implementing the RecordHelper interface from ReflectionHelper
      Object proxy = java.lang.reflect.Proxy.newProxyInstance(
          recordHelperClass.getClassLoader(),
          new Class<?>[]{recordHelperClass},
          (proxyObj, method, args) -> {
            if ("getRecordComponentNames".equals(method.getName()) && args.length == 1) {
              return expected;
            }
            return null;
          });

      // Set the proxy instance to the RECORD_HELPER field
      recordHelperField.set(null, proxy);

      String[] actual = ReflectionHelper.getRecordComponentNames(recordClassMock);
      assertArrayEquals(expected, actual);
    } catch (Exception e) {
      fail("Exception during test: " + e);
    }
  }

  // Dummy record class mock for testing
  private static class RecordClassMock {
    // Empty class, just for test
  }
}
